<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
</template>
    
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from '../HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                // FindalLocationArray: [],          
                FormSchema: [{
                        layoutType: "triple",
                        Data: [{
                                astype: "MultiSelectField",
                                label: this.$t("Project Status"),
                                name: "ProjectStatus",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Project Status'),
                                mode: "tag",
                                config: {
                                    options: [],
                                },
                                validationRules: {
                                    "required": false
                                }
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Work Type"),
                                name: "WorkType",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('All of the Work Types'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Billable Work Type', value:1}, {name:'Non-Billable Work type', value:0}]
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Team Members"),
                                name: "TeamMember",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Team members'),
                                mode: "tag",
                                config: {
                                    options: [],
    
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Project Type"),
                                name: "ProjectType",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('All of the Work Types'),
                                mode: "tag",
                                config: {
                                    options: [{name:'HOURLY', value:1}, {name:'FIXED', value:0}]
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Project"),
                                name: "Project",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Project(s)'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    onChange: this.Getlient
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Client"),
                                name: "Client",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Client'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                        ],
                    },
                    
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;
            await vm.GetUsers();
            await vm.GetProjectList();
            await vm.Getlient();
            await  vm.GetStatusList();
        },
        methods: {
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "projectwisesummaryreport",
                    StatusIds:  e.ProjectStatus.length > 0 ? e.ProjectStatus.map(item => item.value).join(",") : '',
                    WorkType:  e.WorkType.length > 0 ? e.WorkType.map(item => item.value).join(",") : '',
                    ProjectType:  e.ProjectType.length > 0 ? e.ProjectType.map(item => item.value).join(",") : '',
                    userIds:  e.TeamMember.length > 0 ? e.TeamMember.map(item => item.value).join(",") : '',
                    projectIds:  e.Project.length > 0 ? e.Project.map(item => item.value).join(",") : '',
                    ClientIds :  e.Client.length > 0 ? e.Client.map(item => item.value).join(",") : '',
                    
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },

            GetProjectList :async function () {
            var vm = this;
            var params = `companyId=${vm.companyId}&userId=${vm.userId}&pmIds=&isIncludeNoProject=`;
            DataServices.GetProjectList(params).then((response) => {
                if (response.data != '') {
                    vm.EmployeeData = JSON.parse(response.data.result);
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[4].config.options.push({
                            name: item.PROJECTNAME,
                            value: item.PROJECTID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetUsers :async function () {
                 
                 var vm = this;
                 var params = `isType=false&moduleName=ProjectReport`;
                 await DataServices.GetUsers(params).then((response) => {
                     if (response.data != '') {
                          
                         vm.EmployeeData = response.data;
                         vm.EmployeeData.forEach(item => {
                             vm.FormSchema[0].Data[2].config.options.push({
                                 name: item.UserName,
                                 value: item.UserId 
                             })
                         })
                     }
                     vm.$refs.BarcodeReport.UpdateKeyValue();
                 });
             },

            Getlient :async function (x,y,z) {
                debugger;
                    var vm = this;
                    if(z != undefined ){
                    var params = `ProjectId=${z.value}`;

                    }
                    else{
                        var params = `ProjectId=`
                    }
                 DataServices.GetClientListByProjectId(params).then((response) => {
                    if (response.data != '') {
                          vm.CLientData = response.data;
                          vm.CLientData.forEach(item => {
                              vm.FormSchema[0].Data[5].config.options.push({
                                  name: item.CLIENTNAME,
                                  value: item.USER_ID 
                              })
                          })
                      }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetStatusList: async function () {
            debugger;
                var vm = this;
                var url = `langCode=en&statusType=Project&hasglobal=false`
                await DataServices.GetStatusList(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.STATUS,
                                value: element.STATUS_ID
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
           
        }
    };
    </script>
    